// src/wxml/shared.ts
import { escape, MappingChars2String } from "@weapp-core/escape";
function replaceWxml(original, options = {
  keepEOL: false,
  escapeMap: MappingChars2String
}) {
  const { keepEOL, escapeMap, ignoreHead } = options;
  let res = original;
  if (!keepEOL) {
    res = res.replaceAll(/[\n\r]+/g, "");
  }
  res = escape(res, {
    map: escapeMap,
    ignoreHead
  });
  return res;
}

